module top_module(
    clk,
    resetn,
    start_enable,
    start_time,
    timer
);parameter WIDTH = 10;

  input clk;
  input resetn;
  input start_enable;
  input [WIDTH-1:0] start_time;
  output [WIDTH-1:0] timer;

  reg [WIDTH-1:0] countdown_timer;

  assign timer = countdown_timer;

  always @(posedge clk) begin
  if (!resetn)
    countdown_timer <= 0;
  else if( start_enable )
    countdown_timer <= start_time;
  else if( countdown_timer > 0 )
    countdown_timer <= countdown_timer - 1'b1;
end

endmodule
